impl Solution { pub fn find_cheapest_price(n: i32, flights: Vec<Vec<i32>>, src: i32, dst: i32, k: i32) -> i32 { let mut black_dist = vec![i32::MAX; n as usize]; black_dist[src as usize] = 0; for _ in 0..=k { let mut black_tmp = black_dist.clone(); for f in &flights { if black_dist[f[0] as usize] != i32::MAX { black_tmp[f[1] as usize] = black_tmp[f[1] as usize].min(black_dist[f[0] as usize] + f[2]); } } black_dist = black_tmp; } if black_dist[dst as usize] == i32::MAX { -1 } else { black_dist[dst as usize] } } }
